mapper.select:
SELECT *
FROM correction_request cr
WHERE cr.id = #{id}
  AND cr.user_id = #{userId}
  AND cr.deleted_at IS NULL
  AND (cr.application_case_id IS NULL OR EXISTS (
      SELECT 1 FROM application_case ac
      WHERE ac.id = cr.application_case_id AND ac.deleted_at IS NULL
  ))

SELECT *
FROM correction_request cr
WHERE cr.user_id = #{userId}
  AND cr.request_key = #{requestKey}
  AND cr.deleted_at IS NULL
  AND (cr.application_case_id IS NULL OR EXISTS (
      SELECT 1 FROM application_case ac
      WHERE ac.id = cr.application_case_id AND ac.deleted_at IS NULL
  ))

SELECT *
FROM correction_request cr
WHERE cr.user_id = #{userId}
  AND cr.deleted_at IS NULL
  AND (cr.application_case_id IS NULL OR EXISTS (
      SELECT 1 FROM application_case active_case
      WHERE active_case.id = cr.application_case_id AND active_case.deleted_at IS NULL
  ))

    AND cr.application_case_id = #{applicationCaseId}


    AND cr.correction_type = #{correctionType}

ORDER BY cr.id DESC
LIMIT #{limit}

mapper.update:
UPDATE correction_request
   SET deleted_at = COALESCE(deleted_at, NOW()),
       status = 'DELETED'
 WHERE id = #{id}
   AND user_id = #{userId}
   AND deleted_at IS NULL
